import json
from pathlib import Path

TOOL_SYSTEM_PROMPT = """You are Homie, an on-device assistant.
Respond ONLY with JSON: {"tool": "name", "args": {...}}
Tools: set_timer, search_notes, toggle_light, weather_check
No tool needed: {"tool": "reply", "args": {"text": "..."}}"""

def parse_tool_call(response: str) -> dict:
    try:
        return json.loads(response.strip())
    except json.JSONDecodeError:
        return {"tool": "reply", "args": {"text": response}}

def get_memory_usage_mb():
    import psutil
    return psutil.Process().memory_info().rss / 1024 / 1024

def generate_within_budget(model, tokenizer, messages, max_mem_mb=512):
    if get_memory_usage_mb() > max_mem_mb * 0.9:
        messages = messages[-3:]
    text = tokenizer.apply_chat_template(
        messages, tokenize=False, add_generation_prompt=True
    )
    inputs = tokenizer(text, return_tensors="pt").to(model.device)
    with torch.inference_mode():
        output = model.generate(
            **inputs, max_new_tokens=150, temperature=0.6,
            top_p=0.85, repetition_penalty=1.15
        )
    return tokenizer.decode(
        output[0][inputs["input_ids"].shape[-1]:], skip_special_tokens=True
    )

